    expect(config.sources.web_pages?.keywords).toEqual(["gpu", "webgpu"]);
  });

  it("rejects invalid web_pages URLs", () => {
    expect(() =>
      parseConfig(`
description: test
sources:
  web_pages:
    urls:
      - not-a-url
`)
    ).toThrow();
  });

